// // This module implements a 4-bit DRAM cell with read and write functionalities.
// The cell has inputs for data (4 bits), a write enable signal (we), and a read enable signal (re).
// When the write enable signal is low, the data should be written to the cell.
// When the read enable signal is low, the current data in the cell should be output.
module dram_cell (
    input wire [3:0] data_in,
    input wire we,
    input wire re,
    output reg [3:0] data_out
);
    reg [3:0] memory;

    always @(posedge we) begin
        memory <= data_in; // Write operation
    end

    always @(posedge re) begin
        data_out <= memory; // Read operation
    end
endmodule

